// src/pages/LandingPage.js
import React, { useState } from "react";
import { registerUser, loginUser } from "../utils/firebase";
import "./LandingPage.css";

const features = [
  { icon: "🎙️", title: "Record & Transcribe", desc: "Speak naturally — Groq's Whisper model converts your voice to text in seconds." },
  { icon: "📊", title: "Instant Metrics",     desc: "Get your WPM, filler word count, and pause patterns analyzed automatically." },
  { icon: "🤖", title: "AI Coaching",         desc: "Receive personalized feedback powered by Claude to help you speak with confidence." },
  { icon: "📈", title: "Track Progress",      desc: "Every session is saved. Watch your scores trend upward over time." },
];

const scenarios = [
  { label: "Thesis Defense",  emoji: "🎓", color: "#7c6cfc" },
  { label: "Job Interview",   emoji: "💼", color: "#fc6c8f" },
  { label: "Recitation",      emoji: "📖", color: "#4ecca3" },
];

export default function LandingPage({ navigate, user, onLogout }) {
  // Modal state
  const [showAuth, setShowAuth] = useState(false);
  const [mode, setMode]         = useState("login");

  // Form state
  const [name, setName]         = useState("");
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [confirm, setConfirm]   = useState("");
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);

  const openModal = (initialMode = "login") => {
    setMode(initialMode);
    setError("");
    setName(""); setEmail(""); setPassword(""); setConfirm("");
    setShowAuth(true);
  };

  const closeModal = () => {
    setShowAuth(false);
    setError("");
  };

  const switchMode = (newMode) => {
    setMode(newMode);
    setError("");
    setName(""); setEmail(""); setPassword(""); setConfirm("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (mode === "register") {
      if (!name.trim())         return setError("Please enter your name.");
      if (password.length < 6)  return setError("Password must be at least 6 characters.");
      if (password !== confirm)  return setError("Passwords do not match.");
    }

    setLoading(true);
    try {
      if (mode === "register") {
        await registerUser(name.trim(), email.trim(), password);
      } else {
        await loginUser(email.trim(), password);
      }
      closeModal(); // auth state change in App.js will update `user` automatically
    } catch (err) {
      const msg = err.code || err.message;
      if (msg.includes("email-already-in-use"))   setError("That email is already registered. Try logging in.");
      else if (msg.includes("user-not-found"))    setError("No account found with that email.");
      else if (msg.includes("wrong-password"))    setError("Incorrect password. Please try again.");
      else if (msg.includes("invalid-email"))     setError("Please enter a valid email address.");
      else if (msg.includes("too-many-requests")) setError("Too many attempts. Please wait a moment and try again.");
      else setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="landing">
      {/* NAV */}
      <nav className="navbar">
        <span className="navbar-logo">CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>Dashboard</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>Start Practice</button>
          {user ? (
            <div className="navbar-user">
              <span className="navbar-name">👋 {user.displayName || user.email}</span>
              <button className="btn btn-ghost" style={{ color: 'var(--accent)' }} onClick={onLogout}>Log Out</button>
            </div>
          ) : (
            <div className="navbar-auth-btns">
              <button className="btn btn-ghost" onClick={() => openModal("login")}>Log In</button>
              <button className="btn btn-outline" onClick={() => openModal("register")}>Register</button>
            </div>
          )}
        </div>
      </nav>

      {/* HERO */}
      <section className="hero">
        <div className="hero-glow" />
        <div className="hero-content">
          <span className="tag tag-purple">AI Speech Coach</span>
          <h1 className="hero-title">
            Speak with<br />
            <span className="hero-gradient">Confidence.</span>
          </h1>
          <p className="hero-sub">
            CLARIO analyzes your speech in real-time — measuring pace, filler words,
            and clarity — then gives you AI-powered coaching to help you improve fast.
          </p>
          <div className="hero-actions">
            <button className="btn btn-primary" onClick={() => navigate("practice")}>
              🎙️ Start a Session
            </button>
            <button className="btn btn-outline" onClick={() => navigate("dashboard")}>
              View My Progress
            </button>
          </div>

          {/* Scenarios */}
          <div className="scenario-chips">
            <span className="scenario-label">Practice scenarios:</span>
            {scenarios.map((s) => (
              <span key={s.label} className="scenario-chip" style={{ "--chip-color": s.color }}>
                {s.emoji} {s.label}
              </span>
            ))}
          </div>
        </div>

        {/* Hero visual */}
        <div className="hero-visual">
          <div className="mock-card">
            <div className="mock-top">
              <span className="mock-label">Live Session</span>
              <span className="tag tag-green">● Recording</span>
            </div>
            <div className="mock-waveform">
              {[...Array(20)].map((_, i) => (
                <div key={i} className="mock-bar" style={{ "--delay": `${i * 0.08}s`, "--h": `${20 + Math.sin(i) * 50}%` }} />
              ))}
            </div>
            <div className="mock-metrics">
              <div className="mock-metric"><span className="mock-val">142</span><span className="mock-key">WPM</span></div>
              <div className="mock-metric"><span className="mock-val">3</span><span className="mock-key">Fillers</span></div>
              <div className="mock-metric"><span className="mock-val">87</span><span className="mock-key">Score</span></div>
            </div>
          </div>
        </div>
      </section>

      {/* FEATURES */}
      <section className="features-section">
        <h2 className="section-title">Everything you need to improve</h2>
        <div className="features-grid">
          {features.map((f) => (
            <div key={f.title} className="feature-card card">
              <span className="feature-icon">{f.icon}</span>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="cta-section">
        <h2>Ready to level up your public speaking?</h2>
        <p>Join thousands of students who practice smarter with CLARIO.</p>
        <button className="btn btn-primary" onClick={() => navigate("practice")}>
          🎙️ Start Your First Session — It's Free
        </button>
      </section>

      <footer className="footer">
        <span className="navbar-logo">CLARIO</span>
        <span>Built with ❤️ by Rolch, Maky, Cholou, Sofia &amp; the team · CMU Technopreneurship 2026</span>
      </footer>

      {/* ── FLOATING AUTH MODAL ── */}
      {showAuth && (
        <div className="auth-overlay" onClick={(e) => e.target === e.currentTarget && closeModal()}>
          <div className="auth-modal">
            {/* Close button */}
            <button className="auth-close" onClick={closeModal} aria-label="Close">✕</button>

            {/* Logo */}
            <div className="auth-logo">CLARIO</div>
            <p className="auth-tagline">AI-Powered Speech Coach</p>

            {/* Tabs */}
            <div className="auth-tabs">
              <button
                className={`auth-tab ${mode === "login" ? "active" : ""}`}
                onClick={() => switchMode("login")}
              >
                Log In
              </button>
              <button
                className={`auth-tab ${mode === "register" ? "active" : ""}`}
                onClick={() => switchMode("register")}
              >
                Register
              </button>
            </div>

            {/* Form */}
            <form className="auth-form" onSubmit={handleSubmit}>
              {mode === "register" && (
                <div className="auth-field">
                  <label>Full Name</label>
                  <input
                    type="text"
                    placeholder="e.g. Maky Aury Okit"
                    value={name}
                    onChange={e => setName(e.target.value)}
                    required
                  />
                </div>
              )}

              <div className="auth-field">
                <label>Email Address</label>
                <input
                  type="email"
                  placeholder="you@email.com"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  required
                />
              </div>

              <div className="auth-field">
                <label>Password</label>
                <input
                  type="password"
                  placeholder={mode === "register" ? "At least 6 characters" : "Your password"}
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                />
              </div>

              {mode === "register" && (
                <div className="auth-field">
                  <label>Confirm Password</label>
                  <input
                    type="password"
                    placeholder="Repeat your password"
                    value={confirm}
                    onChange={e => setConfirm(e.target.value)}
                    required
                  />
                </div>
              )}

              {error && <p className="auth-error">⚠️ {error}</p>}

              <button className="btn btn-primary auth-submit" type="submit" disabled={loading}>
                {loading
                  ? <><span className="auth-spinner" /> {mode === "register" ? "Creating account..." : "Logging in..."}</>
                  : mode === "register" ? "Create Account" : "Log In"
                }
              </button>
            </form>

            {/* Switch mode */}
            <p className="auth-switch">
              {mode === "login"
                ? <>Don't have an account? <button onClick={() => switchMode("register")}>Register here</button></>
                : <>Already have an account? <button onClick={() => switchMode("login")}>Log in here</button></>
              }
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
